#include <bits/stdc++.h>
using namespace std;
string s;
int main(){
    cin>>s;
    int sum=0;
    for(int i=0,m=1;i<s.size()-2;i++){
        if(s[i]=='-')continue;
        sum+=m*(s[i]-'0');
        m++;
    }
    sum%=11;
    char c=sum+'0';
    if(c>'9')c='X';
    if(s[12]==c)cout<<"Right";
    else{
        s[12]=c;
        cout<<s;
    }
    return 0;
}
